import React, { useMemo } from 'react';

interface YouTubeEmbedProps {
  url: string;
  className?: string;
  title?: string;
}

export const YouTubeEmbed: React.FC<YouTubeEmbedProps> = ({ url, className = "", title = "Video" }) => {
  const videoId = useMemo(() => {
    try {
      if (!url) return null;
      const urlObj = new URL(url);
      if (urlObj.hostname.includes('youtube.com')) {
        return urlObj.searchParams.get('v');
      } else if (urlObj.hostname.includes('youtu.be')) {
        return urlObj.pathname.slice(1);
      }
      return null;
    } catch (e) {
      return null;
    }
  }, [url]);

  if (!videoId) {
    return (
      <div className={`flex items-center justify-center bg-slate-200 text-slate-500 rounded-lg ${className}`}>
        <p className="text-sm">Invalid Video URL</p>
      </div>
    );
  }

  return (
    <div className={`relative overflow-hidden rounded-xl shadow-md bg-black ${className}`}>
      <iframe
        className="absolute top-0 left-0 w-full h-full"
        src={`https://www.youtube.com/embed/${videoId}`}
        title={title}
        frameBorder="0"
        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
        allowFullScreen
      />
    </div>
  );
};

import React, { useState } from 'react';
import { explainPattern } from '../services/geminiService';
import { Sparkles, X, Loader2 } from 'lucide-react';

interface PatternAssistantProps {
  pattern: string;
  className: string;
}

export const PatternAssistant: React.FC<PatternAssistantProps> = ({ pattern, className }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [explanation, setExplanation] = useState<string | null>(null);

  const handleAsk = async () => {
    setIsOpen(true);
    if (!explanation) {
      setLoading(true);
      const result = await explainPattern(pattern, className);
      setExplanation(result);
      setLoading(false);
    }
  };

  return (
    <>
      <button 
        onClick={handleAsk}
        className="ml-2 inline-flex items-center text-xs text-rose-600 hover:text-rose-700 font-medium transition-colors"
        title="Ask AI Instructor"
      >
        <Sparkles className="w-3 h-3 mr-1" />
        <span className="sr-only">Explain {pattern}</span>
      </button>

      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full p-6 relative animate-in fade-in zoom-in duration-200">
            <button 
              onClick={() => setIsOpen(false)}
              className="absolute top-4 right-4 text-slate-400 hover:text-slate-600"
            >
              <X className="w-5 h-5" />
            </button>

            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 bg-rose-100 text-rose-600 rounded-full">
                <Sparkles className="w-5 h-5" />
              </div>
              <h3 className="text-lg font-bold text-slate-800">AI Assistant</h3>
            </div>

            <p className="font-semibold text-slate-700 mb-2">
              Explaining: <span className="text-rose-600">{pattern}</span>
            </p>

            <div className="bg-slate-50 p-4 rounded-xl text-slate-600 text-sm leading-relaxed min-h-[100px]">
              {loading ? (
                <div className="flex items-center justify-center h-24">
                  <Loader2 className="w-6 h-6 animate-spin text-rose-500" />
                  <span className="ml-2 text-slate-400">Consulting the knowledge base...</span>
                </div>
              ) : (
                explanation
              )}
            </div>

            <div className="mt-4 flex justify-end">
              <button 
                onClick={() => setIsOpen(false)}
                className="px-4 py-2 bg-slate-900 text-white text-sm font-medium rounded-lg hover:bg-slate-800 transition-colors"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

