import React, { useState, useMemo } from 'react';
import { VideoItem, SongItem } from '../types';
import { YouTubeEmbed } from './YouTubeEmbed';
import { Play, Music2, Headphones, Flame, Disc } from 'lucide-react';

interface MediaViewProps {
  videos: VideoItem[];
  songs: SongItem[];
}

export const MediaView: React.FC<MediaViewProps> = ({ videos, songs }) => {
  const tutorials = useMemo(() => videos.filter(v => v.category === 'tutorial'), [videos]);
  const [selectedVideoId, setSelectedVideoId] = useState<string>(tutorials[0]?.id || '');

  const selectedVideo = tutorials.find(v => v.id === selectedVideoId);

  const getSongsByCategory = (cat: string) => songs.filter(s => s.category === cat).slice(0, 5);

  const newSongs = getSongsByCategory('new');
  const bluesSongs = getSongsByCategory('blues');
  const practiceSongs = getSongsByCategory('practice');

  return (
    <div className="space-y-8 pb-20">
      {/* Tutorials Section */}
      <section className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b border-slate-100">
           <h2 className="text-2xl font-bold text-slate-800 mb-4 flex items-center gap-2">
             <div className="p-2 bg-rose-100 text-rose-600 rounded-lg">
               <Play className="w-5 h-5 fill-current" />
             </div>
             Video Tutorials
           </h2>

           <div className="relative">
             <select 
               className="w-full appearance-none bg-slate-50 border border-slate-200 text-slate-700 py-3 px-4 pr-8 rounded-xl leading-tight focus:outline-none focus:bg-white focus:border-rose-500 transition-colors"
               value={selectedVideoId}
               onChange={(e) => setSelectedVideoId(e.target.value)}
             >
               {tutorials.length === 0 && <option>No tutorials available</option>}
               {tutorials.map(v => (
                 <option key={v.id} value={v.id}>{v.title}</option>
               ))}
             </select>
             <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-4 text-slate-500">
               <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
             </div>
           </div>
        </div>

        <div className="p-6 bg-slate-900 flex justify-center">
           {selectedVideo ? (
             <YouTubeEmbed url={selectedVideo.url} title={selectedVideo.title} className="w-full max-w-3xl aspect-video rounded-xl shadow-2xl ring-1 ring-white/10" />
           ) : (
             <div className="h-64 flex items-center justify-center text-slate-500">Select a video to play</div>
           )}
        </div>
      </section>

      {/* Music Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <SongList title="New Songs" icon={<Flame className="w-5 h-5" />} songs={newSongs} color="rose" />
        <SongList title="Blues Songs" icon={<Music2 className="w-5 h-5" />} songs={bluesSongs} color="indigo" />
        <SongList title="Practice Songs" icon={<Headphones className="w-5 h-5" />} songs={practiceSongs} color="emerald" />
      </div>
    </div>
  );
};

interface SongListProps {
  title: string;
  icon: React.ReactNode;
  songs: SongItem[];
  color: 'rose' | 'indigo' | 'emerald';
}

const SongList: React.FC<SongListProps> = ({ title, icon, songs, color }) => {
  const colorStyles = {
    rose: 'text-rose-600 bg-rose-50 border-rose-100',
    indigo: 'text-indigo-600 bg-indigo-50 border-indigo-100',
    emerald: 'text-emerald-600 bg-emerald-50 border-emerald-100',
  };

  const linkStyles = {
    rose: 'hover:bg-rose-50 hover:text-rose-700',
    indigo: 'hover:bg-indigo-50 hover:text-indigo-700',
    emerald: 'hover:bg-emerald-50 hover:text-emerald-700',
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 flex flex-col h-full">
      <div className={`p-4 border-b ${colorStyles[color]} rounded-t-2xl flex items-center gap-2 font-bold`}>
        {icon}
        {title}
      </div>
      <div className="p-2 flex-1">
        {songs.length === 0 ? (
          <div className="p-4 text-center text-slate-400 text-sm">No songs added yet.</div>
        ) : (
          <ul className="space-y-1">
            {songs.map(song => (
              <li key={song.id}>
                <a 
                  href={song.url} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className={`group flex items-center justify-between p-3 rounded-lg transition-all ${linkStyles[color]}`}
                >
                  <div className="flex flex-col overflow-hidden">
                    <span className="font-semibold text-slate-800 text-sm truncate">{song.title}</span>
                    <span className="text-xs text-slate-500 truncate">{song.artist}</span>
                  </div>
                  <div className="text-slate-300 group-hover:text-current transition-colors">
                    <Disc className="w-4 h-4" />
                  </div>
                </a>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

