    console.warn("Spreadsheet ID not set. Using default data.");
    // Simulate network delay for realistic feel
    await new Promise(resolve => setTimeout(resolve, 800));
    return DEFAULT_DATA;
  }

  try {
    const [classes, videos, songs] = await Promise.all([
      fetchTab<DanceClass>('Classes'),
      fetchTab<VideoItem>('Videos'),
      fetchTab<SongItem>('Songs')
    ]);

    // Simple validation to ensure we got something back
    if (classes.length === 0 && videos.length === 0 && songs.length === 0) {
      throw new Error("No data found in sheets");
    }

    return { classes, videos, songs };
  } catch (error) {
    console.error("Failed to fetch sheet data, falling back to defaults:", error);
    return DEFAULT_DATA;
  }
};

/**
 * Helper to fetch a specific tab and parse CSV
 */
async function fetchTab<T>(tabName: string): Promise<T[]> {
  const response = await fetch(`${BASE_URL}${tabName}`);

  if (!response.ok) {
    throw new Error(`Failed to fetch tab: ${tabName}`);
  }

  const csvText = await response.text();

  return new Promise((resolve, reject) => {
    Papa.parse(csvText, {
      header: true,
      skipEmptyLines: true,
      transformHeader: (header) => header.trim().toLowerCase(), // Normalize headers to lowercase
      complete: (results) => {
        // Map keys from CSV to expected Types based on simple matching
        // This assumes CSV headers are somewhat similar to JSON keys (e.g. "Song Title" -> "title")
        const formattedData = results.data.map((row: any) => {
           // Basic mapping logic - add more cases if CSV headers are wildly different
           return normalizeKeys(row);
        });
        resolve(formattedData as T[]);
      },
      error: (err: Error) => reject(err)
    });
  });
}

// Helper to handle loose CSV header matching
function normalizeKeys(row: any): any {
  const newRow: any = {};
  for (const key in row) {
    const val = row[key];
    if (key.includes('id')) newRow.id = val;
    else if (key.includes('name') || key.includes('class')) newRow.name = val;
    else if (key.includes('title')) newRow.title = val;
    else if (key.includes('artist')) newRow.artist = val;
    else if (key.includes('url') || key.includes('link')) newRow.url = val;
    else if (key.includes('cat')) newRow.category = val; // matches 'category'
    else if (key.includes('pat')) newRow.patterns = val; // matches 'patterns'
    else if (key.includes('note')) newRow.notes = val;
    else newRow[key] = val; // fallback
  }
  return newRow;
}

