import { AppData, DanceClass, VideoItem, SongItem } from '../types';
import Papa from 'papaparse';

// User provided Spreadsheet ID and Tab Name
const SPREADSHEET_ID = '1VuTfGDldybCC8Lv0FSQG8acMSQ681X93NgUVAXg89Ls';
const SHEET_NAME = 'webapp data';

// URL to fetch the specific sheet as CSV
const CSV_URL = `https://docs.google.com/spreadsheets/d/${SPREADSHEET_ID}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(SHEET_NAME)}`;

// Default data used as fallback if fetch fails
const DEFAULT_DATA: AppData = {
  classes: [
    { id: '1', name: 'Level 1: Foundations', patterns: 'Left Side Pass, Underarm Turn', notes: 'Keep the connection elastic.' },
    { id: '2', name: 'Level 2: Intermediate', patterns: 'Whip, Inside Roll', notes: 'Focus on the prep count.' },
    { id: '3', name: 'Level 3: Musicality', patterns: 'Hit the Break', notes: 'Listen to the bass.' },
    { id: '4', name: 'WCS Tech', patterns: 'Anchor Step', notes: 'Roll through the feet.' }
  ],
  videos: [
    { id: 'vom', title: 'Video of the Month', url: 'https://www.youtube.com/watch?v=2vjPBrBU-TM', category: 'month' }
  ],
  songs: [
    { id: 's1', title: 'Example Song', artist: 'Artist', url: 'https://youtube.com', category: 'new' }
  ]
};

/**
 * Fetches data from the specific Google Sheet layout.
 */
export const fetchSheetData = async (): Promise<AppData> => {
  try {
    const response = await fetch(CSV_URL);
    if (!response.ok) {
      throw new Error(`Failed to fetch sheet: ${response.statusText}`);
    }

    const csvText = await response.text();

    return new Promise((resolve) => {
      Papa.parse(csvText, {
        header: false, // We use fixed indices based on the provided layout
        skipEmptyLines: false, // Must be false to preserve row indices (e.g. A29 must be index 28)
        complete: (results) => {
          const rows = results.data as string[][];

          // Helper to safely get a cell value. 
          // row is 0-indexed (Row 1 in sheet is index 0)
          const getCell = (r: number, c: number) => {
            return rows[r] && rows[r][c] ? rows[r][c].trim() : '';
          };

          // --- 1. Classes ---
          // Sheet Rows 2-5 -> Array Indices 1-4
          // A=Name, B=Patterns, C=Notes
          const classes: DanceClass[] = [];
          for (let i = 1; i <= 4; i++) {
            if (getCell(i, 0)) {
              classes.push({
                id: `class-${i}`,
                name: getCell(i, 0),
                patterns: getCell(i, 1),
                notes: getCell(i, 2)
              });
            }
          }

          const songs: SongItem[] = [];

          // --- 2. New Music ---
          // Sheet Rows 8-12 -> Array Indices 7-11
          // A=Title, B=Artist, C=Youtube Link
          for (let i = 7; i <= 11; i++) {
            if (getCell(i, 0)) {
              songs.push({
                id: `new-${i}`,
                title: getCell(i, 0),
                artist: getCell(i, 1),
                url: getCell(i, 2),
                category: 'new'
              });
            }
          }

          // --- 3. Blues Music ---
          // Sheet Rows 15-19 -> Array Indices 14-18
          for (let i = 14; i <= 18; i++) {
            if (getCell(i, 0)) {
              songs.push({
                id: `blues-${i}`,
                title: getCell(i, 0),
                artist: getCell(i, 1),
                url: getCell(i, 2),
                category: 'blues'
              });
            }
          }

          // --- 4. Practice Songs ---
          // Sheet Rows 22-26 -> Array Indices 21-25
          for (let i = 21; i <= 25; i++) {
            if (getCell(i, 0)) {
              songs.push({
                id: `practice-${i}`,
                title: getCell(i, 0),
                artist: getCell(i, 1),
                url: getCell(i, 2),
                category: 'practice'
              });
            }
          }

          // --- 5. Video of the Month ---
          // Sheet Row 29 -> Array Index 28
          // A=Link
          const videos: VideoItem[] = [];
          const vomLink = getCell(28, 0);
          if (vomLink) {
            videos.push({
              id: 'vom',
              title: 'Video of the Month',
              url: vomLink,
              category: 'month'
            });
          }

          // Note: Tutorial videos were not mapped in the provided sheet layout.
          // They will default to empty list.

          resolve({ classes, videos, songs });
        },
        error: (err) => {
          console.error("CSV Parse Error:", err);
          resolve(DEFAULT_DATA);
        }
      });
    });

  } catch (error) {
    console.error("Data Service Error:", error);
    return DEFAULT_DATA;
  }
};

import { GoogleGenAI } from "@google/genai";

// Initialize the client strictly using process.env.API_KEY as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Explains a dance pattern using Gemini.
 * @param patternName The name of the dance pattern.
 * @param className The context (e.g., "West Coast Swing").
 */
export const explainPattern = async (patternName: string, className: string): Promise<string> => {
  try {
    const prompt = `
      You are an expert dance instructor. 
      Briefly explain the dance pattern "${patternName}" in the context of "${className}".
      Focus on the key mechanical steps or feeling. Keep it under 50 words.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.0-flash-exp',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // Low latency preferred for UI tooltips
      }
    });

    if (response.text) {
        return response.text;
    }
    return "Could not generate an explanation at this time.";

  } catch (error) {
    console.error("Gemini API Error:", error);
    return "AI Assistant is currently unavailable. Please check your API key.";
  }
};

/**
 * Extracts search keywords from an audio recording of a user voice query.
 * @param audioBase64 Base64 encoded audio string (raw data from recorder).
 * @param mimeType The mime type of the audio (e.g., 'audio/webm' or 'audio/mp4').
 */
export const parseVoiceSearch = async (audioBase64: string, mimeType: string): Promise<string> => {
  try {
    const prompt = "Listen to this audio. The user is searching for a song, artist, or genre in a dance music library. Extract the text search query. Return ONLY the search terms as text. If no search term is detected, return empty string.";

    const response = await ai.models.generateContent({
      model: 'gemini-2.0-flash-exp',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: audioBase64
            }
          },
          { text: prompt }
        ]
      }
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Gemini Voice Search Error:", error);
    return "";
  }
};

