export const YouTubeEmbed: React.FC<YouTubeEmbedProps> = ({ url, className = "", title = "Video" }) => {
  const videoId = useMemo(() => {
    try {
      if (!url) return null;

      let processUrl = url.trim();
      // Handle cases where users paste "www.youtube.com" without https://
      if (!processUrl.match(/^https?:\/\//)) {
        processUrl = `https://${processUrl}`;
      }

      const urlObj = new URL(processUrl);

      if (urlObj.hostname.includes('youtube.com')) {
        // Handle normal watch URLs
        if (urlObj.searchParams.get('v')) {
           return urlObj.searchParams.get('v');
        }
        // Handle embed URLs just in case
        if (urlObj.pathname.startsWith('/embed/')) {
           return urlObj.pathname.split('/')[2];
        }
        // Handle shorts
        if (urlObj.pathname.startsWith('/shorts/')) {
           return urlObj.pathname.split('/')[2];
        }
      } else if (urlObj.hostname.includes('youtu.be')) {
        return urlObj.pathname.slice(1);
      }
      return null;
    } catch (e) {
      console.warn("Invalid YouTube URL:", url);
