import { AppData, DanceClass, VideoItem, SongItem } from '../types';
import Papa from 'papaparse';

// We use the standard Spreadsheet ID (not the 2PACX published ID) to allow selecting a specific tab by name.
const SPREADSHEET_ID = '1VuTfGDldybCC8Lv0FSQG8acMSQ681X93NgUVAXg89Ls';
const SHEET_NAME = 'webapp data';

// The gviz/tq endpoint allows us to specify 'sheet=webapp data' query parameter.
// We explicitly request range A1:E50 to ensure the API returns the exact grid we expect from the top.
// We add 'headers=0' to ensure the API doesn't treat the first row as a header and skip it.
// We add a 'select' query to force the return of columns A-E, ensuring structure.
// We add a cache buster (t) to prevent stale data.
const CSV_URL = `https://docs.google.com/spreadsheets/d/${SPREADSHEET_ID}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(SHEET_NAME)}&range=A1:E50&headers=0&tq=${encodeURIComponent('select A,B,C,D,E')}&t=${Date.now()}`;

// Default data used as fallback if fetch fails
const DEFAULT_DATA: AppData = {
  classes: [],
  videos: [],
  songs: []
};

/**
 * Fetches data from the specific Google Sheet layout.
 */
export const fetchSheetData = async (): Promise<AppData> => {
  try {
    const response = await fetch(CSV_URL);
    if (!response.ok) {
      throw new Error(`Failed to fetch sheet: ${response.statusText}`);
    }

    const csvText = await response.text();

    return new Promise((resolve) => {
      Papa.parse(csvText, {
        header: false, // We use fixed indices based on the user's specific layout
        skipEmptyLines: false, // Must be false to preserve row indices
        complete: (results) => {
          const rows = results.data as string[][];

          // Debug log to help diagnose row offset issues
          // console.log("Parsed Rows Sample:", rows.slice(0, 5));

          // Helper to safely get a cell value. 
          // row is 0-indexed (Row 1 in sheet is index 0)
          const getCell = (r: number, c: number) => {
            return rows[r] && rows[r][c] ? rows[r][c].trim() : '';
          };

          // --- 1. Classes ---
          // User spec: A2:C5 (4 classes) -> Indices 1-4
          // A=Class Name, B=Content, C=Notes
          const classes: DanceClass[] = [];
          for (let i = 1; i <= 4; i++) {
            const name = getCell(i, 0);
            // Only add if name exists, but allow empty content/notes
            if (name) {
              classes.push({
                id: `class-${i}`,
                name: name,
                content: getCell(i, 1),
                notes: getCell(i, 2)
              });
            }
          }

          const songs: SongItem[] = [];

          // Helper to find row index by header content (case-insensitive partial match)
          const findRowByHeader = (search: string, startFrom = 0): number => {
            for (let i = startFrom; i < rows.length; i++) {
              if (rows[i][0] && rows[i][0].toLowerCase().includes(search.toLowerCase())) {
                return i;
              }
            }
            return -1;
          };

          // --- 2. New Music ---
          // User spec: A8:C12 (5 songs) -> Indices 7-11
          // A=Title, B=Artist, C=Youtube Link
          // We use absolute indices but fallback to searching if data seems shifted
          // If row 7 is empty or not what we expect, we could search, but for now we trust the top section is stable.
          // Note: The CSV export often skips empty rows, so absolute indices can be risky for lower sections.

          // Strategy: Try to find headers if possible, otherwise fall back to estimated offsets based on empty row skipping.
          // Standard skipping: 1 header + 4 classes + 1 empty + 1 header = Index 7? 
          // Actually if row 6 is empty and skipped: 1(H) + 4(C) + 1(H) = Index 6 starts "New Music"?
          // Let's stick to the user's indices for the top part as they haven't complained, 
          // but for Video of the Month (far down), we use search.

          for (let i = 7; i <= 11; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('music')) { // Simple check to avoid headers
              songs.push({
                id: `new-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: getCell(i, 2),
                category: 'new'
              });
            }
          }

          // --- 3. Blues Music ---
          // User spec: A15:C19 (5 songs) -> Indices 14-18
          for (let i = 14; i <= 18; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('music')) {
              songs.push({
                id: `blues-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: getCell(i, 2),
                category: 'blues'
              });
            }
          }

          // --- 4. Practice Songs ---
          // User spec: A22:C26 (5 songs) -> Indices 21-25
          for (let i = 21; i <= 25; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('songs')) {
              songs.push({
                id: `practice-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: getCell(i, 2),
                category: 'practice'
              });
            }
          }

          const videos: VideoItem[] = [];

          // --- 5. Video of the Month ---
          // User spec: A29
          // Because GViz CSV export often skips empty rows, the absolute index 28 (row 29) might be incorrect (shifted up).
          // We search for the header "Video of the Month" to locate it accurately.
          let vomIndex = findRowByHeader('video of the month');

          // If found, the video link is in the next row.
          // If not found, we fallback to a likely index calculated based on skipped rows (Index 24) or the user's original (Index 28).
          // Given the user report that Index 28 -> A34, we know the data is compressed.
          if (vomIndex === -1) {
             vomIndex = 23; // Fallback estimate (Header at 23, Data at 24)
          }

          const vomLink = getCell(vomIndex + 1, 0);

          if (vomLink && vomLink.startsWith('http')) {
            videos.push({
              id: 'vom',
              title: 'Video of the Month',
              url: vomLink,
              category: 'month'
            });
          } else if (getCell(28, 0).startsWith('http')) {
             // Absolute fallback if search failed and 28 looks like a link
             videos.push({
              id: 'vom',
              title: 'Video of the Month',
              url: getCell(28, 0),
              category: 'month'
            });
          }

          resolve({ classes, videos, songs });
        },
        error: (err) => {
          console.error("CSV Parse Error:", err);
          resolve(DEFAULT_DATA);
        }
      });
    });

  } catch (error) {
    console.error("Data Service Error:", error);
    return DEFAULT_DATA;
  }
};

import React, { useMemo } from 'react';

interface YouTubeEmbedProps {
