    const cleanUrl = url.trim();

    // Helper to sanitize extracted ID
    const sanitizeId = (id: string | null | undefined) => {
      if (!id) return null;
      // Remove any trailing slashes, question marks, or ampersands if they leaked through
      const clean = id.replace(/[\/?&].*$/, '').trim();
      // Basic validation: IDs are usually 11 chars, but can be slightly different for playlists (though we are targeting videos)
      // Allow alphanumeric, underscore, hyphen.
      if (/^[a-zA-Z0-9_-]{10,}$/.test(clean)) {
        return clean;
      }
      return null;
    };

    // 1. Direct ID check
    if (/^[a-zA-Z0-9_-]{11}$/.test(cleanUrl)) {
      return cleanUrl;
    }

    try {
      let processUrl = cleanUrl;
      // Handle cases where users paste "www.youtube.com" without https://
      if (!processUrl.match(/^https?:\/\//)) {
        processUrl = `https://${processUrl}`;
      }

      const urlObj = new URL(processUrl);
      const hostname = urlObj.hostname.toLowerCase();

      let extractedId = null;

      if (hostname.includes('youtube.com')) {
        // Handle normal watch URLs: ?v=ID
        if (urlObj.searchParams.get('v')) {
           extractedId = urlObj.searchParams.get('v');
        }
        // Handle embed URLs: /embed/ID
        else if (urlObj.pathname.startsWith('/embed/')) {
           extractedId = urlObj.pathname.split('/')[2];
        }
        // Handle shorts: /shorts/ID
        else if (urlObj.pathname.startsWith('/shorts/')) {
           extractedId = urlObj.pathname.split('/')[2];
        }
        // Handle live: /live/ID
        else if (urlObj.pathname.startsWith('/live/')) {
           extractedId = urlObj.pathname.split('/')[2];
        }
      } else if (hostname.includes('youtu.be')) {
        // Handle short URLs: youtu.be/ID
        extractedId = urlObj.pathname.slice(1);
      }

      return sanitizeId(extractedId);

    } catch (e) {
      console.warn("Invalid YouTube URL:", url);
      return null;
    }
  }, [url]);

  if (!videoId) {
    return (
      <div className={`flex items-center justify-center bg-slate-800 text-slate-500 rounded-lg border border-slate-700 border-dashed p-8 ${className}`}>
        <div className="text-center">
            <p className="font-medium text-slate-400">Invalid Video URL</p>
            <p className="text-xs mt-1 text-slate-500 max-w-[200px] truncate mx-auto">{url || "Empty URL"}</p>
        </div>
      </div>
    );
  }

  return (
    <div className={`relative overflow-hidden rounded-xl shadow-md bg-black ${className}`}>
      <iframe
        className="absolute top-0 left-0 w-full h-full"
        src={`https://www.youtube.com/embed/${videoId}?rel=0`}
        title={title}
        frameBorder="0"
        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
