const CSV_URL = `https://docs.google.com/spreadsheets/d/${SPREADSHEET_ID}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(SHEET_NAME)}&range=A1:E50&headers=0&tq=${encodeURIComponent('select A,B,C,D,E')}&t=${Date.now()}`;

// Default data used as fallback if fetch fails
const DEFAULT_DATA: AppData = {
  classes: [],
  videos: [],
  songs: []
};

/**
 * Fetches data from the specific Google Sheet layout.
 */
export const fetchSheetData = async (): Promise<AppData> => {
  try {
    const response = await fetch(CSV_URL);
    if (!response.ok) {
      throw new Error(`Failed to fetch sheet: ${response.statusText}`);
    }

    const csvText = await response.text();

    return new Promise((resolve) => {
      Papa.parse(csvText, {
        header: false, // We use fixed indices based on the user's specific layout
        skipEmptyLines: false, // Must be false to preserve row indices
        complete: (results) => {
          const rows = results.data as string[][];

          // Debug log to help diagnose row offset issues
          // console.log("Parsed Rows Sample:", rows.slice(0, 5));

          // Helper to safely get a cell value. 
          // row is 0-indexed (Row 1 in sheet is index 0)
          const getCell = (r: number, c: number) => {
            return rows[r] && rows[r][c] ? rows[r][c].trim() : '';
          };

          // Helper: Extract first URL from text if present, otherwise return text
          const extractUrl = (text: string): string => {
            const match = text.match(/https?:\/\/[^\s"']+/);
            return match ? match[0] : text;
          };

          // --- 1. Classes ---
          // User spec: A2:C5 (4 classes) -> Indices 1-4
          // A=Class Name, B=Content, C=Notes
          const classes: DanceClass[] = [];
          for (let i = 1; i <= 4; i++) {
            const name = getCell(i, 0);
            // Only add if name exists, but allow empty content/notes
            if (name) {
              classes.push({
                id: `class-${i}`,
                name: name,
                content: getCell(i, 1),
                notes: getCell(i, 2)
              });
            }
          }

          const songs: SongItem[] = [];

          // Helper to find row index by header content (case-insensitive partial match)
          const findRowByHeader = (search: string, startFrom = 0): number => {
            for (let i = startFrom; i < rows.length; i++) {
              if (rows[i][0] && rows[i][0].toLowerCase().includes(search.toLowerCase())) {
                return i;
              }
            }
            return -1;
          };

          // --- 2. New Music ---
          // User spec: A8:C12 (5 songs) -> Indices 7-11
          // A=Title, B=Artist, C=Youtube Link
          for (let i = 7; i <= 11; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('music')) { // Simple check to avoid headers
              songs.push({
                id: `new-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: extractUrl(getCell(i, 2)),
                category: 'new'
              });
            }
          }

          // --- 3. Blues Music ---
          // User spec: A15:C19 (5 songs) -> Indices 14-18
          for (let i = 14; i <= 18; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('music')) {
              songs.push({
                id: `blues-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: extractUrl(getCell(i, 2)),
                category: 'blues'
              });
            }
          }

          // --- 4. Practice Songs ---
          // User spec: A22:C26 (5 songs) -> Indices 21-25
          for (let i = 21; i <= 25; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('songs')) {
              songs.push({
                id: `practice-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: extractUrl(getCell(i, 2)),
                category: 'practice'
              });
            }
          }

          const videos: VideoItem[] = [];

          // --- 5. Video of the Month ---
          // Search for the header "Video of the Month" to locate it accurately.
          let vomIndex = findRowByHeader('video of the month');

          if (vomIndex === -1) {
             vomIndex = 23; // Fallback estimate
          }

          // We check the cell below the header
          const rawVomCell = getCell(vomIndex + 1, 0);
          const cleanVomUrl = extractUrl(rawVomCell);

          if (cleanVomUrl && cleanVomUrl.startsWith('http')) {
            videos.push({
              id: 'vom',
              title: 'Video of the Month',
              url: cleanVomUrl,
              category: 'month'
            });
          } else {
             // Absolute fallback if search failed check rigid index 28 (row 29)
             const fallbackCell = getCell(28, 0);
             if (fallbackCell.startsWith('http')) {
                videos.push({
                  id: 'vom',
                  title: 'Video of the Month',
                  url: extractUrl(fallbackCell),
                  category: 'month'
                });
             }
          }

          resolve({ classes, videos, songs });
        },
        error: (err) => {
          console.error("CSV Parse Error:", err);
          resolve(DEFAULT_DATA);
        }
      });
    });

  } catch (error) {
    console.error("Data Service Error:", error);
    return DEFAULT_DATA;
  }
};

import React, { useMemo } from 'react';

interface YouTubeEmbedProps {
  url: string;
  className?: string;
  title?: string;
}

export const YouTubeEmbed: React.FC<YouTubeEmbedProps> = ({ url, className = "", title = "Video" }) => {
  const videoId = useMemo(() => {
    if (!url) return null;
    const cleanUrl = url.trim();

    // 1. Direct ID check (Standard IDs are 11 chars)
    if (/^[a-zA-Z0-9_-]{11}$/.test(cleanUrl)) {
      return cleanUrl;
    }

    // 2. Robust Regex Extraction for all YouTube formats
    // Covers: youtube.com/watch?v=ID, youtu.be/ID, /embed/, /shorts/, /live/, etc.
    const regExp = /^.*(?:(?:youtu\.be\/|v\/|vi\/|u\/\w\/|embed\/|shorts\/|live\/)|(?:(?:watch)?\?v(?:i)?=|\&v(?:i)?=))([^#\&\?]*).*/;
    const match = cleanUrl.match(regExp);

    if (match && match[1]) {
        // IDs are typically 11 chars, but we allow 10-12 to be safe against slight variations
        if (match[1].length >= 10 && match[1].length <= 12) {
            return match[1];
        }
    }

    return null;
  }, [url]);

  if (!videoId) {
    return (
      <div className={`flex items-center justify-center bg-slate-800 text-slate-500 rounded-lg border border-slate-700 border-dashed p-8 ${className}`}>
        <div className="text-center">
            <p className="font-medium text-slate-400">Invalid Video URL</p>
            <p className="text-xs mt-1 text-slate-500 max-w-[200px] truncate mx-auto">{url || "Empty URL"}</p>
        </div>
      </div>
    );
  }

  // Get current origin for the iframe src to prevent configuration errors
  const origin = typeof window !== 'undefined' ? window.location.origin : '';

  return (
    <div className={`relative overflow-hidden rounded-xl shadow-md bg-black ${className}`}>
      <iframe
        className="absolute top-0 left-0 w-full h-full"
        src={`https://www.youtube.com/embed/${videoId}?rel=0&origin=${origin}`}
        title={title}
        frameBorder="0"
        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
        allowFullScreen
      />
    </div>
  );
};

