          if (cleanVomUrl && (cleanVomUrl.startsWith('http') || /^[a-zA-Z0-9_-]{11}$/.test(cleanVomUrl))) {
            videos.push({
              id: 'vom',
              title: 'Video of the Month',
              url: cleanVomUrl,
              category: 'month'
            });
          } else {
             // Absolute fallback if search failed check rigid index 28 (row 29)
             const fallbackCell = getCell(28, 0);
             const fallbackUrl = extractUrl(fallbackCell);
             if (fallbackUrl.startsWith('http') || /^[a-zA-Z0-9_-]{11}$/.test(fallbackUrl)) {
                videos.push({
                  id: 'vom',
                  title: 'Video of the Month',
                  url: fallbackUrl,
                  category: 'month'
                });
             }
          }

          // --- 6. Announcements ---
          // User spec: A33:B43 -> Indices 32-42
          // A=Date, B=Text
          const announcements: Announcement[] = [];
          for (let i = 32; i <= 42; i++) {
            const date = getCell(i, 0);
            const text = getCell(i, 1);
            // Only add if there is text
            if (text) {
              announcements.push({
                id: `ann-${i}`,
