import Papa from 'papaparse';

// We use the standard Spreadsheet ID
const SPREADSHEET_ID = '1VuTfGDldybCC8Lv0FSQG8acMSQ681X93NgUVAXg89Ls';
const SHEET_NAME = 'webapp data';

// Increased range to E100 to ensure we capture all data even if rows are inserted
const CSV_URL = `https://docs.google.com/spreadsheets/d/${SPREADSHEET_ID}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(SHEET_NAME)}&range=A1:E100&headers=0&tq=${encodeURIComponent('select A,B,C,D,E')}&t=${Date.now()}`;

// Default data used as fallback if fetch fails
const DEFAULT_DATA: AppData = {
  classes: [],
  videos: [],
  songs: [],
  announcements: []
};

/**
 * Fetches data from the specific Google Sheet layout.
 */
export const fetchSheetData = async (): Promise<AppData> => {
  try {
    const response = await fetch(CSV_URL);
    if (!response.ok) {
      throw new Error(`Failed to fetch sheet: ${response.statusText}`);
    }

    const csvText = await response.text();

    return new Promise((resolve) => {
      Papa.parse(csvText, {
        header: false, 
        skipEmptyLines: false, // Keep this false to maintain relative row positions as much as possible
        complete: (results) => {
          const rows = results.data as string[][];

          // Helper to safely get a cell value. 
          const getCell = (r: number, c: number) => {
            return rows[r] && rows[r][c] ? rows[r][c].trim() : '';
          };

          // Helper: Extract first URL from text if present
          const extractUrl = (text: string): string => {
            const match = text.match(/https?:\/\/[^\s"']+/);
            if (match) {
              return match[0].replace(/[,.)\]}]+$/, '');
            }
            return text;
          };

          // Helper: Find row index by header content
          const findRowByHeader = (search: string, startFrom = 0): number => {
            for (let i = startFrom; i < rows.length; i++) {
              // Check column A and B for the header text
              const cellA = rows[i][0] ? rows[i][0].toLowerCase() : '';
              const cellB = rows[i][1] ? rows[i][1].toLowerCase() : '';
              if (cellA.includes(search.toLowerCase()) || cellB.includes(search.toLowerCase())) {
                return i;
              }
            }
            return -1;
          };

          // --- 1. Classes ---
          // Indices 1-4 (Rows 2-5)
          const classes: DanceClass[] = [];
          for (let i = 1; i <= 4; i++) {
            const name = getCell(i, 0);
            if (name) {
              classes.push({
                id: `class-${i}`,
                name: name,
                content: getCell(i, 1),
                notes: getCell(i, 2)
              });
            }
          }

          const songs: SongItem[] = [];

          // --- 2. New Music ---
          // Indices 7-11 (Rows 8-12)
          for (let i = 7; i <= 11; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('music')) { 
              songs.push({
                id: `new-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: extractUrl(getCell(i, 2)),
                category: 'new'
              });
            }
          }

          // --- 3. Blues Music ---
          // Indices 14-18 (Rows 15-19)
          for (let i = 14; i <= 18; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('music')) {
              songs.push({
                id: `blues-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: extractUrl(getCell(i, 2)),
                category: 'blues'
              });
            }
          }

          // --- 4. Practice Songs ---
          // Indices 21-25 (Rows 22-26)
          for (let i = 21; i <= 25; i++) {
            const title = getCell(i, 0);
            if (title && !title.toLowerCase().includes('songs')) {
              songs.push({
                id: `practice-${i}`,
                title: title,
                artist: getCell(i, 1),
                url: extractUrl(getCell(i, 2)),
                category: 'practice'
              });
            }
          }

          const videos: VideoItem[] = [];

          // --- 5. Video of the Month ---
          let vomIndex = findRowByHeader('video of the month', 20); // Start searching after songs

          if (vomIndex === -1) {
             vomIndex = 28; // Fallback index if header not found
          } else {
             // If found, data is likely in the next row
             vomIndex = vomIndex + 1;
          }

          const rawVomCell = getCell(vomIndex, 0);
          const cleanVomUrl = extractUrl(rawVomCell);

          if (cleanVomUrl && (cleanVomUrl.startsWith('http') || /^[a-zA-Z0-9_-]{11}$/.test(cleanVomUrl))) {
            videos.push({
              id: 'vom',
              title: 'Video of the Month',
              url: cleanVomUrl,
              category: 'month'
            });
          }

          // --- 6. Announcements ---
          // User spec: A33:B43 -> Indices 32-42
          // Strategy: Look for "Announcements" header after row 25. 
          // If found, start from next row. If not, default to index 32.

          const announcements: Announcement[] = [];

          let annStartIndex = findRowByHeader('announcements', 25);
          if (annStartIndex === -1) {
            annStartIndex = findRowByHeader('news', 25);
          }

          let dataStart = 32; // Default to Row 33 (index 32)

          if (annStartIndex !== -1) {
            dataStart = annStartIndex + 1;
          }

          // If the row at dataStart looks like a sub-header (e.g. "Date" / "Text"), skip it
          if (getCell(dataStart, 0).toLowerCase() === 'date' || getCell(dataStart, 1).toLowerCase() === 'text') {
             dataStart++;
          }

          // Read up to 15 rows from the start point
          for (let i = dataStart; i < dataStart + 15; i++) {
            const date = getCell(i, 0);
            const text = getCell(i, 1);

            // Stop if we hit something that looks like another section or end of file
            if (!date && !text) continue;
            if (date.toLowerCase().includes('video') || date.toLowerCase().includes('class')) break;

            if (text) {
              announcements.push({
                id: `ann-${i}`,
                date: date,
                text: text
              });
            }
          }

          resolve({ classes, videos, songs, announcements });
        },
        error: (err) => {
          console.error("CSV Parse Error:", err);
          resolve(DEFAULT_DATA);
        }
      });
    });

  } catch (error) {
    console.error("Data Service Error:", error);
    return DEFAULT_DATA;
  }
};

